# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import machine
import time
from umqtt.simple import MQTTClient

# Set up ESP32 pin for DHT22 (or your sensor)
dht = machine.Pin(5, machine.Pin.IN)

# Connect to the MQTT broker
client_id = "ESP32Sensor"
broker_ip = "192.168.1.100"

# Create an MQTT client instance
mqtt_client = MQTTClient(client_id, broker_ip)

try:
    # Connect to the MQTT broker
    mqtt_client.connect()
    
    while True:
        # Read temperature from DHT22 (or your sensor)
        temperature = dht.read()
        
        # Publish temperature readings to "sensors/temp" topic
        mqtt_client.publish(b"sensors/temp", str(temperature).encode())
        
        # Wait 10 seconds before publishing again
        time.sleep(10)
except Exception as e:
    print(e)
finally:
    # Disconnect from the MQTT broker when we're done
    mqtt_client.disconnect()